using namespace std;
int s[1005];
int sfind(int x) {
	if (x == s[x])	return x;
	else return s[x] = sfind(s[x]);
}
bool smerge(int i, int x) {
	int fi = sfind(i);
	int fx = sfind(x);
	if (fi == fx) {
		return false;
	}
    s[fx] = fi;
    return true;
}
